CREATE OR REPLACE FUNCTION fpa_fin_pay_chq_receive ( as_vourcher_no text ) RETURNS varchar AS $body$
DECLARE

  ls_receive_name varchar(1000);

BEGIN

    SELECT CASE WHEN  sc_fin_cheque_print.by_other ='1' THEN  sc_fin_cheque_print.receive_name    ELSE sc_fin_cheque_print.paid_name2 END
    into STRICT ls_receive_name
    FROM sc_fin_cheque_print_item
    , sc_fin_m_bank
   , sc_fin_cheque_print
    where 1=1    
    and sc_fin_cheque_print.bank_fin = sc_fin_cheque_print_item.bank_fin
    and sc_fin_cheque_print.book_no = sc_fin_cheque_print_item.book_no
    and sc_fin_cheque_print.cheque_no = sc_fin_cheque_print_item.cheque_no
    and sc_fin_cheque_print.seq_no = sc_fin_cheque_print_item.seq_no
    and sc_fin_cheque_print.cancel_status = '0'
    and sc_fin_m_bank.bank_fin = sc_fin_cheque_print_item.bank_fin
    and sc_fin_cheque_print_item.vourcher_no = 'P6705080'  
    and sc_fin_cheque_print_item.seq_no = ( SELECT max( seq_no )
                FROM sc_fin_cheque_print_item
                where sc_fin_cheque_print_item.vourcher_no = 'P6705080' 
                ) 
;
  return ls_receive_name;

exception when others then return '';
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
-- REVOKE ALL ON FUNCTION fpa_fin_pay_chq_receive ( as_vourcher_no text ) FROM PUBLIC;

